  TYPE polygon
  PROCESSING 'LABEL_NO_CLIP=1'
  CLASSITEM "simbolo"  
  TRANSPARENCY 100
  DUMP true
  TEMPLATE void 
  DATA "the_geom from (select gid, fisiografia, simbolo, the_geom from geo.mapa_geomorfologico_ima) as siar using unique gid using srid=32718"
